import { useState, useEffect, useMemo } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  Card,
  Button,
  Form,
  Row,
  Col,
  Spinner,
  Alert,
  Container,
  Badge,
} from "react-bootstrap";
import { getEventById } from "../services/eventService";
import { createOrder } from "../services/orderService";

function EventDetailPage() {
  const { eventId } = useParams();
  const navigate = useNavigate();

  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [selectedTickets, setSelectedTickets] = useState({});
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const fetchEventDetails = async () => {
      try {
        setLoading(true);
        setError("");

        if (!eventId) {
          setError("ID sự kiện không hợp lệ.");
          return;
        }

        const response = await getEventById(eventId);

        if (response.data?.success && response.data?.data) {
          setEvent(response.data.data);
          setTicketTypes(response.data.data.ticket_types || []);
        } else {
          setError("Không có thông tin sự kiện.");
        }
      } catch (err) {
        console.error("Lỗi lấy chi tiết sự kiện:", err);
        setError("Lỗi khi tải chi tiết sự kiện.");
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetails();
  }, [eventId]);

  const renderStatusBadge = (status) => {
    switch (status) {
      case "on_sale":
        return <Badge bg="success">Đang mở bán</Badge>;
      case "upcoming":
        return (
          <Badge bg="warning" text="dark">
            Sắp diễn ra
          </Badge>
        );
      case "sold_out":
        return <Badge bg="secondary">Hết vé</Badge>;
      case "ended":
        return <Badge bg="dark">Đã kết thúc</Badge>;
      default:
        return <Badge bg="info">{status}</Badge>;
    }
  };

  const handleQuantityChange = (ticket, value) => {
    const rawValue = Number(value);

    const quantityAvailable =
      ticket.quantity_available ??
      ticket.quantity_total - (ticket.quantity_sold || 0);

    const maxAllowed = Math.min(
      ticket.max_per_order || 1,
      Math.max(quantityAvailable, 0)
    );

    let finalValue = Number.isNaN(rawValue) ? 0 : rawValue;

    if (finalValue < 0) finalValue = 0;
    if (finalValue > maxAllowed) finalValue = maxAllowed;

    setSelectedTickets((prev) => ({
      ...prev,
      [ticket.id]: finalValue,
    }));
  };

  const selectedItems = useMemo(() => {
    return ticketTypes
      .map((ticket) => {
        const quantity = Number(selectedTickets[ticket.id] || 0);
        return {
          ...ticket,
          selected_quantity: quantity,
          line_total: Number(ticket.price) * quantity,
        };
      })
      .filter((ticket) => ticket.selected_quantity > 0);
  }, [ticketTypes, selectedTickets]);

  const totalQuantity = useMemo(() => {
    return selectedItems.reduce((sum, item) => sum + item.selected_quantity, 0);
  }, [selectedItems]);

  const totalAmount = useMemo(() => {
    return selectedItems.reduce((sum, item) => sum + item.line_total, 0);
  }, [selectedItems]);

  const handleCreateOrder = async () => {
    try {
      const items = selectedItems.map((item) => ({
        ticket_type_id: item.id,
        quantity: item.selected_quantity,
      }));

      if (items.length === 0) {
        alert("Vui lòng chọn ít nhất 1 loại vé.");
        return;
      }

      setSubmitting(true);

      const payload = { items };

      const response = await createOrder(payload);

      if (response.data?.success && response.data?.data?.id) {
        const orderId = response.data.data.id;
        alert("Tạo đơn hàng thành công.");
        navigate(`/payment/${orderId}`);
      } else {
        alert(response.data?.message || "Tạo đơn hàng thất bại.");
      }
    } catch (err) {
      console.error("Lỗi tạo order:", err);
      const message =
        err?.response?.data?.message ||
        err?.message ||
        "Lỗi khi tạo đơn hàng.";
      alert(message);
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "100vh" }}
      >
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  if (error) {
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="my-5">
        <Alert variant="warning">Không tìm thấy sự kiện.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row className="g-4 mb-5">
        <Col md={6}>
          <img
            src={
              event.banner_image
                ? `/images/${event.banner_image}`
                : "/images/default-banner.jpg"
            }
            alt={event.title}
            style={{
              width: "100%",
              height: "100%",
              maxHeight: "420px",
              objectFit: "cover",
              borderRadius: "12px",
            }}
            onError={(e) => {
              e.target.src = "/images/default-banner.jpg";
            }}
          />
        </Col>

        <Col md={6}>
          <div className="d-flex align-items-center gap-2 mb-3">
            <h2 className="mb-0">{event.title}</h2>
            {renderStatusBadge(event.status)}
          </div>

          <p>
            <strong>Mô tả:</strong> {event.description || "Không có mô tả"}
          </p>

          <p>
            <strong>Địa điểm:</strong> {event.location || "Chưa cập nhật"}
          </p>

          <p>
            <strong>Ngày tổ chức:</strong>{" "}
            {event.event_date
              ? new Date(event.event_date).toLocaleString("vi-VN")
              : "Chưa cập nhật"}
          </p>

          <p>
            <strong>Ban tổ chức:</strong>{" "}
            {event.organizer_name || "Chưa cập nhật"}
          </p>
        </Col>
      </Row>

      <Row className="mb-3">
        <Col>
          <h4>Chọn loại vé</h4>
        </Col>
      </Row>

      {ticketTypes.length === 0 ? (
        <Alert variant="warning">Sự kiện này hiện chưa có loại vé nào.</Alert>
      ) : (
        <Row className="g-4">
          <Col lg={8}>
            <Row>
              {ticketTypes.map((ticket) => {
                const quantityAvailable =
                  ticket.quantity_available ??
                  ticket.quantity_total - (ticket.quantity_sold || 0);

                const maxAllowed = Math.min(
                  ticket.max_per_order || 1,
                  Math.max(quantityAvailable, 0)
                );

                const selectedQuantity = selectedTickets[ticket.id] || 0;
                const isSoldOut = quantityAvailable <= 0;

                return (
                  <Col key={ticket.id} md={6}>
                    <Card className="mb-4 h-100 shadow-sm">
                      <Card.Body>
                        <div className="d-flex justify-content-between align-items-start mb-2">
                          <Card.Title className="mb-0">{ticket.name}</Card.Title>
                          {isSoldOut ? (
                            <Badge bg="secondary">Hết vé</Badge>
                          ) : (
                            <Badge bg="success">Đang bán</Badge>
                          )}
                        </div>

                        <Card.Text>
                          {ticket.description || "Không có mô tả"}
                        </Card.Text>

                        <Card.Text>
                          <strong>Giá:</strong>{" "}
                          {Number(ticket.price).toLocaleString("vi-VN")} VNĐ
                        </Card.Text>

                        <Card.Text>
                          <strong>Còn lại:</strong> {quantityAvailable}
                        </Card.Text>

                        <Card.Text>
                          <strong>Tối đa / đơn:</strong> {ticket.max_per_order}
                        </Card.Text>

                        <Form.Group className="mt-3">
                          <Form.Label>Số lượng</Form.Label>
                          <Form.Control
                            type="number"
                            min={0}
                            max={maxAllowed}
                            value={selectedQuantity}
                            disabled={isSoldOut}
                            onChange={(e) =>
                              handleQuantityChange(ticket, e.target.value)
                            }
                          />
                          <Form.Text className="text-muted">
                            {isSoldOut
                              ? "Loại vé này đã hết."
                              : `Bạn có thể chọn tối đa ${maxAllowed} vé.`}
                          </Form.Text>
                        </Form.Group>
                      </Card.Body>
                    </Card>
                  </Col>
                );
              })}
            </Row>
          </Col>

          <Col lg={4}>
            <Card className="shadow-sm sticky-top" style={{ top: "100px" }}>
              <Card.Body>
                <h5 className="mb-3">Đơn hàng của bạn</h5>

                {selectedItems.length === 0 ? (
                  <Alert variant="light" className="mb-0">
                    Bạn chưa chọn vé nào.
                  </Alert>
                ) : (
                  <>
                    {selectedItems.map((item) => (
                      <div
                        key={item.id}
                        className="d-flex justify-content-between align-items-start mb-3 pb-3 border-bottom"
                      >
                        <div>
                          <div className="fw-bold">{item.name}</div>
                          <div className="text-muted small">
                            {item.selected_quantity} x{" "}
                            {Number(item.price).toLocaleString("vi-VN")} VNĐ
                          </div>
                        </div>
                        <div className="fw-bold text-primary">
                          {Number(item.line_total).toLocaleString("vi-VN")} VNĐ
                        </div>
                      </div>
                    ))}

                    <div className="d-flex justify-content-between mb-2">
                      <span>Tổng số vé</span>
                      <strong>{totalQuantity}</strong>
                    </div>

                    <div className="d-flex justify-content-between mb-3">
                      <span>Tổng tiền</span>
                      <strong className="text-danger">
                        {Number(totalAmount).toLocaleString("vi-VN")} VNĐ
                      </strong>
                    </div>

                    <div className="d-grid">
                      <Button
                        variant="primary"
                        onClick={handleCreateOrder}
                        disabled={submitting}
                      >
                        {submitting ? "Đang tạo đơn..." : "Mua vé ngay"}
                      </Button>
                    </div>
                  </>
                )}
              </Card.Body>
            </Card>
          </Col>
        </Row>
      )}
    </Container>
  );
}

export default EventDetailPage;
